
import ZAI from 'z-ai-web-dev-sdk';

async function main() {
  const zai = await ZAI.create();
  const response = await zai.chat.completions.createVision({
    messages: [{
      role: 'user',
      content: [
        { type: 'text', text: 'Describe all the errors, broken UI elements, and issues you see in this admin app screenshot. Focus on layout problems, missing elements, broken sections, and any visual bugs. Be specific and detailed.' },
        { type: 'image_url', image_url: { url: 'data:image/jpeg;base64,' } }
      ]
    }],
    thinking: { type: 'disabled' }
  });
  console.log(response.choices[0]?.message?.content);
}
main().catch(e => console.error(e.message));
